import{_ as i,I as e,o as s,c as o,aq as n,J as l,aH as d,aI as p,aJ as g}from"./chunks/framework.kV0qpqqq.js";const _=JSON.parse('{"title":"连接篇","description":"","frontmatter":{},"headers":[],"relativePath":"Guides/astrobox/AstroboxV1连接篇.md","filePath":"Guides/astrobox/AstroboxV1连接篇.md","lastUpdated":1773512079000}'),h={name:"Guides/astrobox/AstroboxV1连接篇.md"};function x(f,t,m,y,c,k){const a=e("NolebaseGitContributors"),r=e("NolebaseGitChangelog");return s(),o("div",null,[t[0]||(t[0]=n('<h1 id="连接篇" tabindex="-1">连接篇 <a class="header-anchor" href="#连接篇" aria-label="Permalink to “连接篇”">​</a></h1><p>::danger</p><p>特别注意：如果在设备页没有显示电量，就代表连接失败！请检查下方事项以解决此问题</p><p>:::</p><h2 id="q1-目前什么手环可以使用" tabindex="-1">Q1：目前什么手环可以使用？ <a class="header-anchor" href="#q1-目前什么手环可以使用" aria-label="Permalink to “Q1：目前什么手环可以使用？”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">型号</th><th style="text-align:left;">状态</th><th style="text-align:left;">备注</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>小米手环 10</strong></td><td style="text-align:left;">✅ 完整支持</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>小米手环 9 Pro</strong></td><td style="text-align:left;">✅ 完整支持</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>小米手环 9</strong></td><td style="text-align:left;">✅ 完整支持</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;">小米手环 8 Pro</td><td style="text-align:left;">❌ 不支持</td><td style="text-align:left;">过时设备</td></tr><tr><td style="text-align:left;">小米手环 8</td><td style="text-align:left;">❌ 不支持</td><td style="text-align:left;">无计划，系统情况无明确资料，协议版本不支持</td></tr><tr><td style="text-align:left;">小米手环 7 及更老机型</td><td style="text-align:left;">❌ 不支持</td><td style="text-align:left;">非 Xiaomi Vela 系统</td></tr><tr><td style="text-align:left;"><strong>小米 Watch S4 系列</strong></td><td style="text-align:left;">✅ 完整支持</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>小米 Watch S3 系列</strong></td><td style="text-align:left;">✅ 完整支持</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;">小米 Watch S2 系列及更老机型</td><td style="text-align:left;">❌ 不支持</td><td style="text-align:left;">协议版本不支持</td></tr><tr><td style="text-align:left;">小米 Watch S1 Pro</td><td style="text-align:left;">❌ 不支持</td><td style="text-align:left;">过时设备</td></tr><tr><td style="text-align:left;"><strong>红米 Watch 6</strong></td><td style="text-align:left;">✅ 完整支持</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>红米 Watch 5</strong></td><td style="text-align:left;">✅ 完整支持</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;">红米 Watch 4</td><td style="text-align:left;">❌ 不支持</td><td style="text-align:left;">过时设备</td></tr><tr><td style="text-align:left;">红米手环系列 / 小米手环 Active 系列</td><td style="text-align:left;">❌ 不支持</td><td style="text-align:left;"></td></tr></tbody></table><h2 id="🌟-q2-如何连接手环" tabindex="-1">🌟 Q2：如何连接手环？ <a class="header-anchor" href="#🌟-q2-如何连接手环" aria-label="Permalink to “🌟 Q2：如何连接手环？”">​</a></h2><p>推荐步骤是：</p><ol><li><p>授予 AstroBox 蓝牙和位置权限</p></li><li><p>登录小米账号 或 使用其他方式获得 Authkey</p></li><li><p>在手机上退出小米运动健康并确保完全关闭（或切换至另一穿戴设备）</p></li><li><p>在手环上进入<mark><strong>连接新设备模式</strong></mark></p></li><li><p>回到设备页面选择设备</p></li><li><p>Authkey 在登录小米账号的状态下会自动为你准备好，直接连接即可；未登录的话直接填入 Authkey 即可</p></li><li><p>Windows 需要在系统蓝牙设置中点击允许配对（可能会在<mark><strong>右下角弹出通知</strong></mark>，点击进去配对即可）</p></li></ol><p><img src="'+d+'" alt="img"></p><h2 id="q3-手环链接后显示请在手机上点击确认-点击后没反应怎么办" tabindex="-1">Q3：手环链接后显示请在手机上点击确认，点击后没反应怎么办？ <a class="header-anchor" href="#q3-手环链接后显示请在手机上点击确认-点击后没反应怎么办" aria-label="Permalink to “Q3：手环链接后显示请在手机上点击确认，点击后没反应怎么办？”">​</a></h2><ol><li><p>检查是否授予 AstroBox 蓝牙和位置权限</p></li><li><p>去蓝牙设置里忽略设备</p></li><li><p>进小米运动健康重连设备</p></li><li><p>深度关闭、停止小米运动健康</p></li><li><p>手环进入连接新手机状态</p></li><li><p>进 AstroBox 设置，重新通过小米账号同步 Authkey</p></li><li><p>进入连接设备页重新连接</p></li></ol><h2 id="q4-如何获得-authkey" tabindex="-1">Q4：如何获得 Authkey？ <a class="header-anchor" href="#q4-如何获得-authkey" aria-label="Permalink to “Q4：如何获得 Authkey？”">​</a></h2><p>你可以直接在应用设置-同步设备 登录小米账号来一键获取，之后可以在连接设备页面里看到所有设备及其 Authkey，你也可以去小米运动健康里拿到 log 查到 Authkey。</p><h2 id="q5-ios-设备登录后-为什么连接设备页面没有自动显示账号里的设备" tabindex="-1">Q5：iOS 设备登录后，为什么连接设备页面没有自动显示账号里的设备？ <a class="header-anchor" href="#q5-ios-设备登录后-为什么连接设备页面没有自动显示账号里的设备" aria-label="Permalink to “Q5：iOS 设备登录后，为什么连接设备页面没有自动显示账号里的设备？”">​</a></h2><p>因为 iOS 平台的特殊性，我们为 iOS 设备设计了新的连接步骤，请参考此文档。</p><h2 id="🌟-q6-为什么我连不上手环-几秒钟手环就断连了" tabindex="-1">🌟 Q6：为什么我连不上手环/几秒钟手环就断连了？ <a class="header-anchor" href="#🌟-q6-为什么我连不上手环-几秒钟手环就断连了" aria-label="Permalink to “🌟 Q6：为什么我连不上手环/几秒钟手环就断连了？”">​</a></h2><p>有任何链接问题请检查：</p><ol><li><p>小米运动健康是否<mark><strong>完全清除后台</strong></mark>（或“小米运动健康”的“附近的设备”权限是否处于关闭状态）</p></li><li><p>表盘自定义工具、Notify For Xiaomi、GadgetBridge等<mark><strong>其它干扰项的权限均为关闭状态</strong></mark>，必要时可以直接卸载。（澎湃OS2用户可以尝试调整“互联互通服务”防止抢连接）</p></li><li><p>手环是否进入<mark><strong>连接新设备模式</strong></mark></p></li><li><p>是否给 AstroBox<mark><strong>“附近的设备”、“蓝牙”、“位置获取”权限</strong></mark></p></li><li><p>电脑请检查是否有<mark><strong>蓝牙模块（4.0+）</strong></mark>，检查有没有在<mark><strong>设置点击确认，手环点击确认</strong></mark></p></li><li><p>请尝试在系统蓝牙设置中<mark><strong>“忽略”你的手环</strong></mark>，然后尝试重新连接<mark><strong>（iOS 用户尤其需要尝试此步）</strong></mark>。Windows由于系统特性可以重启电脑再试。</p></li><li><p>如果<mark><strong>固件有更新版本</strong></mark>请在系统设置里<mark><strong>自行更新</strong></mark></p></li><li><p>安卓版本是否在<mark><strong>13 以上</strong></mark></p></li></ol><p>如果还是无法解决请多次重启手环、应用</p><h2 id="🌟-q7-显示-密钥错误或后端异常-怎么办" tabindex="-1">🌟 Q7：显示“密钥错误或后端异常”怎么办 <a class="header-anchor" href="#🌟-q7-显示-密钥错误或后端异常-怎么办" aria-label="Permalink to “🌟 Q7：显示“密钥错误或后端异常”怎么办”">​</a></h2><p><img src="'+p+'" alt="img"></p><p>首先检查你的设备是否能在 AstroBox 中使用，详情点击<a href="#q1目前什么手环可以使用">此处</a></p><p>如果设备在支持列表中，请检查你的 Authkey 是否正确，有些设备会频繁更新 Authkey，需要你回到运动健康再次连接更新后，将手环进入连接新手机状态，再次进入 AstroBox 登录小米账号获取。</p><h2 id="q8-显示-连接失败-spp-location-permission" tabindex="-1">Q8：显示“连接失败…SPP…LOCATION permission” <a class="header-anchor" href="#q8-显示-连接失败-spp-location-permission" aria-label="Permalink to “Q8：显示“连接失败…SPP…LOCATION permission””">​</a></h2><p><img src="'+g+'" alt="img"></p><p>请你检查是否授予 AstroBox 蓝牙和位置权限</p><p>:::note</p><p>本教程由Yulimfish，川.，wuhaiqi等人编写，本人（lladlam）仅为第三方转载，著作权归Yulimfish，川.，wuhaiqi等人所有</p><p>:::</p>',30)),l(a),l(r)])}const A=i(h,[["render",x]]);export{_ as __pageData,A as default};
